#include<bits/stdc++.h>
using namespace std;
int main(){
	int n,a[101],num=0,g,s,b,q,c=0;
	cin>>n;
	for(int i=0;i<n;i++){
		cin>>a[i];
		g=a[i]%10;
		s=a[i]%100/10;
		b=a[i]/100%10;
		q=a[i]/1000;
		c=g-s;
		c=c-b;
		c=c-q;
		if(c>0){
			num++;
		}
	}cout<<num;
	
    return 0;
}
